def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            base = (ratio - 7) ** 6
            for a in range(7, 3, -1):
                for b in range(1, a + 5):
                    weight = np.exp(-b / (a + 1)) * ((ratio - a) ** 4) / (a * (b + 0.8))
                    priority += weight * np.sin(ratio * b / (a + 1.2)) * np.cos(ratio / (a + b))
            priority += (np.sinh(ratio - 7) * np.cos(ratio * 1.3)) ** 2
            if i % 2 == 0:
                priority += np.log1p(priority + 1) * 3
            else:
                priority -= np.exp(-priority / (ratio + 0.1)) * 2.5
        elif 5 < ratio <= 8:
            temp = 0
            for p in range(1, 15):
                for q in range(p, p + 5):
                    temp += np.tanh((ratio - p) ** 2 / (q + 0.3)) * np.sin(ratio * q) / (p + q)
            priority = temp * np.log(ratio) * 5
            if bin_cap < item * 1.2:
                priority += np.sqrt(item * ratio / (bin_cap + 1)) * 7
            else:
                priority -= np.cos(ratio * 15) * 5
            if i % 3 == 1:
                priority += np.sin(ratio * i * 2) * 2.1
            else:
                priority -= np.cos(ratio * i * 1.5) * 2.1
        elif 3 <= ratio <= 5:
            s1 = 0
            for r in range(1, 16):
                s1 += ((ratio - 3) ** r) / (r ** 1.5 + 1) * np.cos(r * ratio * 0.9)
            s2 = 0
            for m in range(1, 8):
                s2 += np.sin(m * ratio * 1.2) / (m * 0.8 + 0.3)
            priority = (s1 * s2) - np.log(ratio + 0.1) * 8 + np.tanh(5 * (5 - ratio)) * 3
            if bin_cap < item * 0.9:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-2 * ratio) * 3.5
        elif 1 <= ratio < 3:
            s = 0
            for n in range(1, 20):
                s += ((3 - ratio) ** n) / (n ** 2 + 0.9) * np.sin(n * ratio)
            priority = s + np.sqrt(ratio) * 4 - np.tanh(2 * (ratio - 1)) * 2.5
            for k in range(1, 6):
                priority += np.cos(k * ratio * i * 0.7) * ((ratio - 1) ** k) / k
            if bin_cap < item * 1.05:
                priority += np.log1p(bin_cap * ratio) * 3.5
            else:
                priority -= np.exp(-1.2 * ratio) * 2
        elif 0.5 <= ratio < 1:
            s3 = 0
            for x in range(1, 12):
                s3 += ((1 - ratio) ** x) / (x + 0.5) * np.cos(x * ratio * 1.1)
            if bin_cap < item * 0.75:
                penalty = np.sqrt(item / (bin_cap + 0.7)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s3 + penalty + np.exp(-1 / (ratio + 0.03)) * 2
            for y in range(1, 5):
                priority += np.sin(y * ratio * (i+1)) * ((ratio - 0.5) ** y) / y
            if (i + int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.5
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
        elif 0.2 <= ratio < 0.5:
            s4 = 0
            for z in range(1, 18):
                s4 += ((0.5 - ratio) ** z) / (z * 3) * np.cos(z * item * 0.8)
            priority = s4 + 1.5 / (bin_cap + 2)
            if int(item * 1.8) % 6 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for w in range(1, 10):
                priority += ((0.5 - ratio) ** w) / (w * 5) * np.sin(item * w * 1.2)
        else:
            s5 = 0
            for v in range(1, 15):
                s5 += ((0.2 - ratio) ** v) / (v * 6) * np.sin(v * item * 0.7)
            priority = s5 + 3 / (bin_cap + 5)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for uu in range(1, 9):
                priority += ((0.2 - ratio) ** uu) / (uu * 8) * np.cos(item * uu * 0.6)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 7
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.1) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        priorities[i] = priority
    return priorities
